import{_ as s,o as a,c as n,ae as e}from"./chunks/framework.C7FLYIpo.js";const r=JSON.parse('{"title":"QA E2E 자동화","description":"qa-lab, qa-channel, 시드된 시나리오, 프로토콜 보고서를 위한 프라이빗 QA 자동화 형태","frontmatter":{"title":"QA E2E 자동화","description":"qa-lab, qa-channel, 시드된 시나리오, 프로토콜 보고서를 위한 프라이빗 QA 자동화 형태"},"headers":[],"relativePath":"concepts/qa-e2e-automation.md","filePath":"concepts/qa-e2e-automation.md","lastUpdated":null}'),l={name:"concepts/qa-e2e-automation.md"};function h(p,i,t,d,o,k){return a(),n("div",null,[...i[0]||(i[0]=[e(`<h1 id="qa-e2e-자동화" tabindex="-1">QA E2E 자동화 <a class="header-anchor" href="#qa-e2e-자동화" aria-label="Permalink to &quot;QA E2E 자동화&quot;">​</a></h1><p>프라이빗 QA 스택은 단일 단위 테스트가 할 수 있는 것보다 더 현실적인 채널 형태의 방식으로 OpenClaw를 테스트하기 위한 것입니다.</p><p>현재 구성 요소:</p><ul><li><code>extensions/qa-channel</code>: DM, 채널, 스레드, 반응, 편집, 삭제 표면이 있는 합성 메시지 채널.</li><li><code>extensions/qa-lab</code>: 트랜스크립트 관찰, 인바운드 메시지 주입, Markdown 보고서 내보내기를 위한 디버거 UI 및 QA 버스.</li><li><code>qa/</code>: 킥오프 태스크 및 기준 QA 시나리오를 위한 리포 기반 시드 에셋.</li></ul><p>현재 QA 운영자 흐름은 두 개의 창으로 구성된 QA 사이트입니다:</p><ul><li>왼쪽: 에이전트가 있는 게이트웨이 대시보드 (Control UI).</li><li>오른쪽: Slack 형태의 트랜스크립트와 시나리오 계획을 표시하는 QA Lab.</li></ul><p>다음으로 실행하십시오:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> qa:lab:up</span></span></code></pre></div><p>이는 QA 사이트를 빌드하고, Docker 기반 게이트웨이 레인을 시작하며, 운영자 또는 자동화 루프가 에이전트에게 QA 미션을 줄 수 있는 QA Lab 페이지를 노출합니다. 여기서 실제 채널 동작을 관찰하고 무엇이 작동했는지, 실패했는지, 차단된 상태로 있는지 기록할 수 있습니다.</p><p>매번 Docker 이미지를 재빌드하지 않고 더 빠른 QA Lab UI 반복을 위해 bind-mounted QA Lab 번들로 스택을 시작하십시오:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> qa</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> docker-build-image</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> qa:lab:build</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> qa:lab:up:fast</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> qa:lab:watch</span></span></code></pre></div><p><code>qa:lab:up:fast</code>는 Docker 서비스를 사전 빌드된 이미지에 유지하고 <code>extensions/qa-lab/web/dist</code>를 <code>qa-lab</code> 컨테이너에 bind-mount합니다. <code>qa:lab:watch</code>는 변경 시 해당 번들을 재빌드하고 QA Lab 에셋 해시가 변경되면 브라우저가 자동으로 새로 로드됩니다.</p><h2 id="리포-기반-시드" tabindex="-1">리포 기반 시드 <a class="header-anchor" href="#리포-기반-시드" aria-label="Permalink to &quot;리포 기반 시드&quot;">​</a></h2><p>시드 에셋은 <code>qa/</code>에 있습니다:</p><ul><li><code>qa/scenarios/index.md</code></li><li><code>qa/scenarios/*.md</code></li></ul><p>이는 QA 계획이 사람과 에이전트 모두에게 보이도록 의도적으로 git에 있습니다. 기준 목록은 다음을 커버할 만큼 충분히 넓어야 합니다:</p><ul><li>DM 및 채널 채팅</li><li>스레드 동작</li><li>메시지 액션 라이프사이클</li><li>cron 콜백</li><li>메모리 회상</li><li>모델 전환</li><li>서브에이전트 핸드오프</li><li>리포 읽기 및 문서 읽기</li><li>Lobster Invaders와 같은 작은 빌드 태스크 하나</li></ul><h2 id="보고" tabindex="-1">보고 <a class="header-anchor" href="#보고" aria-label="Permalink to &quot;보고&quot;">​</a></h2><p><code>qa-lab</code>은 관찰된 버스 타임라인에서 Markdown 프로토콜 보고서를 내보냅니다. 보고서는 다음에 답해야 합니다:</p><ul><li>무엇이 작동했는가</li><li>무엇이 실패했는가</li><li>무엇이 차단된 상태로 있었는가</li><li>어떤 후속 시나리오를 추가할 가치가 있는가</li></ul><p>캐릭터 및 스타일 검사를 위해 여러 라이브 모델 참조에서 동일한 시나리오를 실행하고 판단된 Markdown 보고서를 작성하십시오:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> qa</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> character-eval</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --model</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> openai/gpt-5.4,thinking=xhigh</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --model</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> openai/gpt-5.2,thinking=xhigh</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --model</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> anthropic/claude-opus-4-6,thinking=high</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --model</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> anthropic/claude-sonnet-4-6,thinking=high</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --model</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> minimax/MiniMax-M2.7,thinking=high</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --model</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> zai/glm-5.1,thinking=high</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --model</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> moonshot/kimi-k2.5,thinking=high</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --model</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> qwen/qwen3.6-plus,thinking=high</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --model</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> xiaomi/mimo-v2-pro,thinking=high</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --model</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> google/gemini-3.1-pro-preview,thinking=high</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --judge-model</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> openai/gpt-5.4,thinking=xhigh,fast</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --judge-model</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> anthropic/claude-opus-4-6,thinking=high</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --concurrency</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 8</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --judge-concurrency</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 8</span></span></code></pre></div><p>이 커맨드는 Docker가 아닌 로컬 QA 게이트웨이 자식 프로세스를 실행합니다. 캐릭터 평가 시나리오는 <code>SOUL.md</code>를 통해 페르소나를 설정한 다음 채팅, 워크스페이스 도움말, 소규모 파일 태스크와 같은 일반 사용자 턴을 실행해야 합니다. 후보 모델에게 평가 중이라고 알려서는 안 됩니다. 이 커맨드는 각 전체 트랜스크립트를 보존하고 기본 실행 통계를 기록한 다음, <code>xhigh</code> 추론이 있는 fast 모드로 판사 모델에게 자연스러움, 분위기, 유머를 기준으로 실행을 순위 매기도록 요청합니다.</p><p>후보 실행은 기본값으로 <code>high</code> thinking을 사용하며, 지원하는 OpenAI 모델에는 <code>xhigh</code>를 사용합니다. <code>--model provider/model,thinking=&amp;lt;level&amp;gt;</code>로 인라인에서 특정 후보를 오버라이드하십시오. <code>--thinking &amp;lt;level&amp;gt;</code>은 여전히 전역 폴백을 설정하며, 이전 <code>--model-thinking &amp;lt;provider/model=level&amp;gt;</code> 형식은 호환성을 위해 유지됩니다.</p><p>OpenAI 후보 참조는 기본적으로 fast 모드로 설정되어 프로바이더가 지원하는 경우 우선 처리가 사용됩니다. 단일 후보 또는 판사에 오버라이드가 필요한 경우 <code>,fast</code>, <code>,no-fast</code>, 또는 <code>,fast=false</code>를 인라인으로 추가하십시오. 모든 후보 모델에 대해 fast 모드를 강제로 활성화하려는 경우에만 <code>--fast</code>를 전달하십시오. 후보 및 판사 실행 시간은 벤치마크 분석을 위해 보고서에 기록되지만, 판사 프롬프트는 속도로 순위를 매기지 말라고 명시적으로 명시합니다.</p><p>후보 및 판사 모델 실행은 모두 기본적으로 동시성 8로 설정됩니다. 프로바이더 한도 또는 로컬 게이트웨이 압력으로 인해 실행이 너무 시끄러워지면 <code>--concurrency</code> 또는 <code>--judge-concurrency</code>를 낮추십시오.</p><p>후보 <code>--model</code>이 전달되지 않으면 캐릭터 평가는 기본값으로 <code>openai/gpt-5.4</code>, <code>openai/gpt-5.2</code>, <code>anthropic/claude-opus-4-6</code>, <code>anthropic/claude-sonnet-4-6</code>, <code>minimax/MiniMax-M2.7</code>, <code>zai/glm-5.1</code>, <code>moonshot/kimi-k2.5</code>, <code>qwen/qwen3.6-plus</code>, <code>xiaomi/mimo-v2-pro</code>, <code>google/gemini-3.1-pro-preview</code>를 사용합니다.</p><p><code>--judge-model</code>이 전달되지 않으면 판사는 기본값으로 <code>openai/gpt-5.4,thinking=xhigh,fast</code> 및 <code>anthropic/claude-opus-4-6,thinking=high</code>를 사용합니다.</p><h2 id="관련-문서" tabindex="-1">관련 문서 <a class="header-anchor" href="#관련-문서" aria-label="Permalink to &quot;관련 문서&quot;">​</a></h2><ul><li><a href="/openclaw-docs-ko/help/testing">테스팅</a></li><li><a href="/openclaw-docs-ko/channels/qa-channel">QA 채널</a></li><li><a href="/openclaw-docs-ko/web/dashboard">대시보드</a></li></ul>`,30)])])}const F=s(l,[["render",h]]);export{r as __pageData,F as default};
